// IsUserAuthorized is the resolver for the isUserAuthorized field.
func (r *compliancePortalFileResolver) IsUserAuthorized(ctx context.Context, obj *types.CompliancePortalFile) (bool, error) {
	scope := coredata.NewScopeFromObjectID(obj.ID)
	visitorService := r.visitor
	compliancePortal := complianceportal.CompliancePortalFromContext(ctx)

	portalFile, err := visitorService.GetPortalFile(ctx, scope, compliancePortal.OrganizationID, obj.ID)
	if err != nil {
		if errors.Is(err, visitor.ErrPortalFileNotFound) || errors.Is(err, visitor.ErrPortalFileNotVisible) {
			return false, gqlutils.NotFoundf(ctx, "compliance portal file %q not found", obj.ID)
		}

		r.logger.ErrorCtx(ctx, "cannot load compliance portal file", log.Error(err))

		return false, gqlutils.Internal(ctx)
	}

	if portalFile.CompliancePortalVisibility == coredata.CompliancePortalVisibilityPublic {
		return true, nil
	}

	identity := authn.IdentityFromContext(ctx)
	if identity == nil {
		return false, nil
	}

	fileAccess, err := visitorService.GetPortalFileAccess(ctx, scope,
		compliancePortal.ID,
		identity.ID,
		obj.ID,
	)
	if err != nil {
		if errors.Is(err, visitor.ErrMembershipNotFound) ||
			errors.Is(err, visitor.ErrUserNotFound) ||
			errors.Is(err, visitor.ErrUserInactive) ||
			errors.Is(err, visitor.ErrDocumentAccessNotFound) {
			return false, nil
		}

		r.logger.ErrorCtx(ctx, "cannot check compliance portal file access", log.Error(err))

		return false, gqlutils.Internal(ctx)
	}

	return fileAccess.Status == coredata.CompliancePortalDocumentAccessStatusGranted, nil
}

// Access is the resolver for the access field.
func (r *compliancePortalFileResolver) Access(ctx context.Context, obj *types.CompliancePortalFile) (*types.DocumentAccess, error) {
	scope := coredata.NewScopeFromObjectID(obj.ID)
	visitorService := r.visitor
	compliancePortal := complianceportal.CompliancePortalFromContext(ctx)

	identity := authn.IdentityFromContext(ctx)
	if identity == nil {
		return nil, nil // User is not authenticated, so no access requested
	}

	access, err := visitorService.GetPortalFileAccess(
		ctx, scope,
		compliancePortal.ID,
		identity.ID,
		obj.ID,
	)
	if err != nil {
		if errors.Is(err, visitor.ErrMembershipNotFound) ||
			errors.Is(err, visitor.ErrUserNotFound) ||
			errors.Is(err, visitor.ErrDocumentAccessNotFound) {
			return nil, nil
		}

		if errors.Is(err, visitor.ErrUserInactive) {
			return nil, gqlutils.Forbidden(ctx, err)
		}

		r.logger.ErrorCtx(ctx, "cannot get file access", log.Error(err))

		return nil, gqlutils.Internal(ctx)
	}

	return &types.DocumentAccess{
		ID:     access.ID,
		Status: access.Status,
	}, nil
}

