// IsUserAuthorized is the resolver for the isUserAuthorized field.
func (r *documentResolver) IsUserAuthorized(ctx context.Context, obj *types.Document) (bool, error) {
	scope := coredata.NewScopeFromObjectID(obj.ID)
	visitorService := r.visitor
	compliancePortal := complianceportal.CompliancePortalFromContext(ctx)

	document, err := visitorService.GetDocument(ctx, scope, compliancePortal.OrganizationID, obj.ID)
	if err != nil {
		if errors.Is(err, visitor.ErrDocumentNotFound) || errors.Is(err, visitor.ErrDocumentNotVisible) || errors.Is(err, coredata.ErrResourceNotFound) {
			return false, gqlutils.NotFoundf(ctx, "document %q not found", obj.ID)
		}

		if _, ok := errors.AsType[*visitor.ErrDocumentArchived](err); ok {
			return false, gqlutils.NotFoundf(ctx, "document %q not found", obj.ID)
		}

		r.logger.ErrorCtx(ctx, "cannot load document", log.Error(err))

		return false, gqlutils.Internal(ctx)
	}

	if document.CompliancePortalVisibility == coredata.CompliancePortalVisibilityPublic {
		return true, nil
	}

	identity := authn.IdentityFromContext(ctx)
	if identity == nil {
		return false, nil
	}

	documentAccess, err := visitorService.GetPortalDocumentAccess(
		ctx, scope,
		compliancePortal.ID,
		identity.ID,
		obj.ID,
	)
	if err != nil {
		if errors.Is(err, visitor.ErrMembershipNotFound) ||
			errors.Is(err, visitor.ErrUserNotFound) ||
			errors.Is(err, visitor.ErrUserInactive) ||
			errors.Is(err, visitor.ErrDocumentAccessNotFound) {
			return false, nil
		}

		r.logger.ErrorCtx(ctx, "cannot check document access", log.Error(err))

		return false, gqlutils.Internal(ctx)
	}

	return documentAccess.Status == coredata.CompliancePortalDocumentAccessStatusGranted, nil
}

// Access is the resolver for the access field.
func (r *documentResolver) Access(ctx context.Context, obj *types.Document) (*types.DocumentAccess, error) {
	scope := coredata.NewScopeFromObjectID(obj.ID)
	visitorService := r.visitor
	compliancePortal := complianceportal.CompliancePortalFromContext(ctx)

	identity := authn.IdentityFromContext(ctx)
	if identity == nil {
		return nil, nil // User is not authenticated, so no access requested
	}

	access, err := visitorService.GetPortalDocumentAccess(
		ctx, scope,
		compliancePortal.ID,
		identity.ID,
		obj.ID,
	)
	if err != nil {
		if errors.Is(err, visitor.ErrMembershipNotFound) ||
			errors.Is(err, visitor.ErrUserNotFound) ||
			errors.Is(err, visitor.ErrDocumentAccessNotFound) {
			return nil, nil
		}

		if errors.Is(err, visitor.ErrUserInactive) {
			return nil, gqlutils.Forbidden(ctx, err)
		}

		r.logger.ErrorCtx(ctx, "cannot get document access", log.Error(err))

		return nil, gqlutils.Internal(ctx)
	}

	return &types.DocumentAccess{
		ID:     access.ID,
		Status: access.Status,
	}, nil
}

